What does this program print?

```cpp
#include <iostream>
class Pt {
    int m_x, m_y;
public:
    Pt(int x, int y) : m_x{x}, m_y{y} {}
    Pt& operator=(const Pt& rhs) {
        m_x = rhs.m_x;
        m_y = rhs.m_y;
        return *this;
    }
    void print() const { std::cout << m_x << ',' << m_y << '\n'; }
};
int main() {
    Pt a{1, 2}, b{3, 4}, c{5, 6};
    a = b = c;
    a.print();
    b.print();
}
```

The class below manages a heap buffer. Can you identify the dangerous bug in `operator=`?

```cpp
class Buf {
    int* m_data;
    int  m_len;
public:
    Buf(int len) : m_len{len}, m_data{new int[len]{}} {}
    ~Buf() { delete[] m_data; }
    Buf& operator=(const Buf& rhs) {
        delete[] m_data;
        m_len  = rhs.m_len;
        m_data = new int[m_len];
        return *this;
    }
};
```

